-- SampleBench analytical database (SQLite).
-- Rebuildable mirror of the lm-bench canonical outputs + collected votes.
-- Source of truth stays in ~/lm-bench; this file is regenerated by build_db.py.

PRAGMA journal_mode = WAL;
PRAGMA foreign_keys = ON;

-- Provenance of the sync that produced this DB.
CREATE TABLE IF NOT EXISTS provenance (
    key        TEXT PRIMARY KEY,
    value      TEXT
);

-- Canonical checkpoint registry (from configs/checkpoints.yaml).
CREATE TABLE IF NOT EXISTS checkpoints (
    id              TEXT PRIMARY KEY,
    label           TEXT,
    family          TEXT,
    dataset         TEXT,
    enabled         INTEGER,
    path            TEXT,
    source          TEXT,
    generation_json TEXT          -- raw generation block (backend, algo, nfe, ...)
);

-- Sample suites (from configs/sample_suites/*.yaml + workflow).
CREATE TABLE IF NOT EXISTS suites (
    suite_id        TEXT PRIMARY KEY,
    dataset         TEXT,
    seq_len         INTEGER,
    n_samples       INTEGER,
    reference_model TEXT,
    config_json     TEXT
);

-- Per-model display + provenance metadata (from curated manifests).
CREATE TABLE IF NOT EXISTS models (
    model_id     TEXT,
    suite_id     TEXT,
    label        TEXT,
    method       TEXT,          -- Autoregressive | Diffusion | Naive baseline
    family       TEXT,
    algo         TEXT,
    nfe          INTEGER,
    is_reference INTEGER DEFAULT 0,
    is_served    INTEGER DEFAULT 0,   -- shown in the web UI
    PRIMARY KEY (model_id, suite_id)
);

-- Curated serving/analysis sample pool (subset of the full corpus).
CREATE TABLE IF NOT EXISTS samples (
    sample_id  TEXT PRIMARY KEY,
    suite_id   TEXT REFERENCES suites(suite_id),
    model_id   TEXT,
    text       TEXT,
    char_len   INTEGER,
    served     INTEGER DEFAULT 0    -- 1 = shipped to the web UI
);
CREATE INDEX IF NOT EXISTS idx_samples_model ON samples(model_id);

-- Metric metadata: direction + display label.
CREATE TABLE IF NOT EXISTS metric_meta (
    metric           TEXT PRIMARY KEY,
    label            TEXT,
    higher_is_better INTEGER
);

-- Canonical per-model metrics (long form) from results/metrics/final_metrics.
CREATE TABLE IF NOT EXISTS metrics (
    suite_id  TEXT,
    model_id  TEXT,
    metric    TEXT REFERENCES metric_meta(metric),
    value     REAL,
    PRIMARY KEY (suite_id, model_id, metric)
);

-- Collected human votes (simulated until the Supabase table is wired).
CREATE TABLE IF NOT EXISTS votes (
    vote_id          TEXT PRIMARY KEY,
    session_id       TEXT,
    battle_id        TEXT,
    choice           TEXT,          -- left | right | tie | both_bad
    winner_model_id  TEXT,
    loser_model_id   TEXT,
    left_model_id    TEXT,
    right_model_id   TEXT,
    left_sample_id   TEXT,
    right_sample_id  TEXT,
    response_time_ms INTEGER,
    app_version      TEXT,
    is_simulated     INTEGER DEFAULT 0
);
CREATE INDEX IF NOT EXISTS idx_votes_choice ON votes(choice);

-- Simulated ground-truth quality (only populated by simulate_votes.py; lets
-- correlate.py validate that the BT fit recovers the planted ranking).
CREATE TABLE IF NOT EXISTS sim_truth (
    model_id TEXT PRIMARY KEY,
    quality  REAL
);

-- Recovered human scores per model (materialized by correlate.py).
CREATE TABLE IF NOT EXISTS model_human_scores (
    suite_id  TEXT,
    model_id  TEXT,
    elo       REAL,
    elo_lo    REAL,
    elo_hi    REAL,
    n_votes   INTEGER,
    PRIMARY KEY (suite_id, model_id)
);

-- Convenience view: decisive votes joined to both sides' model metrics (wide-ish,
-- one row per (vote, metric)) for sample/model-level feature analysis.
DROP VIEW IF EXISTS vote_metric_deltas;
CREATE VIEW vote_metric_deltas AS
SELECT v.vote_id, v.choice,
       v.left_model_id, v.right_model_id,
       ml.metric,
       ml.value AS left_value,
       mr.value AS right_value,
       (ml.value - mr.value) AS delta_left_minus_right,
       CASE v.choice WHEN 'left' THEN 1 WHEN 'right' THEN 0 END AS human_picks_left
FROM votes v
JOIN metrics ml ON ml.model_id = v.left_model_id  AND ml.suite_id = (SELECT suite_id FROM suites LIMIT 1)
JOIN metrics mr ON mr.metric = ml.metric AND mr.model_id = v.right_model_id AND mr.suite_id = ml.suite_id
WHERE v.choice IN ('left', 'right');
